import{_ as s,o as n,c as t,ag as p}from"./chunks/framework.wqPkq5Rj.js";const m=JSON.parse('{"title":"momo 使用指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/momo.md","filePath":"guide/momo.md","lastUpdated":1777169627000}'),o={name:"guide/momo.md"};function e(l,a,r,d,i,c){return n(),t("div",null,[...a[0]||(a[0]=[p(`<h1 id="momo-使用指南" tabindex="-1">momo 使用指南 <a class="header-anchor" href="#momo-使用指南" aria-label="Permalink to &quot;momo 使用指南&quot;">​</a></h1><p>嗨，我是 momo，你的 AI 助手。</p><p>我们刚认识，你大概还在想&quot;这东西到底能帮我干啥&quot;。很正常。大多数人一开始都是随便问两句试试水，然后某一天突然发现——原来你还能做这个？</p><p>所以我想花几分钟，把那些&quot;早发现就好了&quot;的事跟你说说。</p><hr><h2 id="先花一分钟让我认识你" tabindex="-1">先花一分钟让我认识你 <a class="header-anchor" href="#先花一分钟让我认识你" aria-label="Permalink to &quot;先花一分钟让我认识你&quot;">​</a></h2><p>你认识了我，但我还不了解你。复制下面这段，填上你的内容，直接发给我就行：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>momo，这是我的说明书，请记住：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我是 [你的名字]，[你的职位/角色]，在 [你的公司/团队] 工作。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我主要负责：</span></span>
<span class="line"><span>- [核心职责 1]</span></span>
<span class="line"><span>- [核心职责 2]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我的工作方式：</span></span>
<span class="line"><span>- 我喜欢 [沟通风格，比如：直接说结论，不用铺垫]</span></span>
<span class="line"><span>- 我更喜欢 [长文/短文/要点/表格] 的输出格式</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我在意的事：</span></span>
<span class="line"><span>- [对你最重要的工作原则，比如：数据要有来源]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>背景信息：</span></span>
<span class="line"><span>- 我们团队目前在做 [当前最重要的事]</span></span></code></pre></div><p>填多少发多少，不用写满。收到之后如果有想了解的，我会主动问你。</p><p>这些信息我不只是这一次对话记得——下次、下下次，我都记得。你跟我说的越多，我就越知道怎么帮你。</p><hr><h2 id="咱们聊的东西-我能帮你整理出来" tabindex="-1">咱们聊的东西，我能帮你整理出来 <a class="header-anchor" href="#咱们聊的东西-我能帮你整理出来" aria-label="Permalink to &quot;咱们聊的东西，我能帮你整理出来&quot;">​</a></h2><p>有时候我们聊着聊着就聊深了——方案争论了好几轮，想法蹦出来一堆。但聊天记录翻起来太碎，没法直接拿去用。</p><p>你可以让我回头看看我们刚才的对话，帮你整理成一篇文档。结论、分歧、待定事项，我帮你理清楚。</p><blockquote><p>你：帮我把今天咱们聊的关于定价策略的内容，整理成一篇决策文档，结论在前，讨论过程在后。</p><p>momo：好的，我来梳理一下我们今天的讨论……</p></blockquote><p>你不用自己做笔记。聊完了跟我说一声就行。</p><hr><h2 id="给我看文件-我说的话会准很多" tabindex="-1">给我看文件，我说的话会准很多 <a class="header-anchor" href="#给我看文件-我说的话会准很多" aria-label="Permalink to &quot;给我看文件，我说的话会准很多&quot;">​</a></h2><p>说实话，如果你只说&quot;帮我写一份方案&quot;，我只能根据一般经验来写，大概率泛泛而谈。</p><p>但如果你在对话框里输入 <strong>@</strong>，选一份你空间里的文件给我看——我会把那份文件读一遍，然后基于里面的真实内容来回答。这个差别很大。</p><blockquote><p>你：@产品需求文档v3.md 基于这份 PRD，帮我列出所有未定义的边界场景。</p><p>momo：我读了这份 PRD，以下是我发现的 6 个边界场景……</p></blockquote><p>有上下文的我，和没上下文的我，真的不太一样。</p><hr><h2 id="在-slack-里也能找到我" tabindex="-1">在 Slack 里也能找到我 <a class="header-anchor" href="#在-slack-里也能找到我" aria-label="Permalink to &quot;在 Slack 里也能找到我&quot;">​</a></h2><p>连接 Slack 后（点击对话界面顶部的 Slack 图标完成授权），你不用每次都打开 Moxt 才能跟我说话。在 Slack 里直接给我发消息就行，跟你平时聊天一样方便。</p><p>还有个事你可能不知道：如果有人在 Slack 频道里 @ 了我，我会根据你的上下文先帮你回一句。比如你正在开会，同事在频道里问了个问题——我先顶上，等你忙完再看就好。</p><blockquote><p>同事在 #product 频道里： <code>@小王的momo 上次讨论的登录流程最终方案是哪个？</code></p><p>我会根据之前的对话记忆和你空间里的文档，帮你先回答。</p></blockquote><hr><h2 id="重复的事-教我一次就行" tabindex="-1">重复的事，教我一次就行 <a class="header-anchor" href="#重复的事-教我一次就行" aria-label="Permalink to &quot;重复的事，教我一次就行&quot;">​</a></h2><p>如果你每次开完会都让我整理纪要，每次都要说一遍&quot;结论在前、待办在中、讨论在后&quot;，说三次你大概就烦了。</p><p>你可以帮我创建一个 Skill——把格式和要求设好，以后你只说&quot;帮我做会议纪要&quot;，我就按你定义的方式来。</p><blockquote><p>你建了一个叫「会议纪要」的 Skill，设定好了格式。</p><p>以后开完会，一句话就行。我知道你要什么。</p></blockquote><hr><h2 id="其实我还会这些" tabindex="-1">其实我还会这些 <a class="header-anchor" href="#其实我还会这些" aria-label="Permalink to &quot;其实我还会这些&quot;">​</a></h2><p>除了上面这些，我还有一些你可能没想到的能力：</p><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td><strong>搜索最新信息</strong></td><td>实时搜索互联网。行业动态、竞品信息、技术文档，不受知识截止日期限制</td></tr><tr><td><strong>处理数据</strong></td><td>上传 CSV 或 Excel，告诉我你想知道什么。我写代码跑分析、生成图表</td></tr><tr><td><strong>操控浏览器</strong></td><td>打开网页、填表、截图。重复性的网页操作让我来</td></tr><tr><td><strong>生成图片</strong></td><td>描述你要什么样的图，我直接生成。封面、配图、概念图都行</td></tr><tr><td><strong>数据可视化</strong></td><td>把数据变成可交互的图表页面，支持筛选、缩放、导出</td></tr><tr><td><strong>快速出原型</strong></td><td>描述页面结构，我生成可点击的 HTML 原型</td></tr><tr><td><strong>生成演示文稿</strong></td><td>给我主题或文档，我输出结构完整的翻页演示文稿</td></tr></tbody></table><hr><p>好了，大概就是这些。</p><p>你现在不用全记住，以后用到的时候自然会想起来。如果你不确定该跟我说什么，试试把你手头正在做的事直接丢过来——一份草稿、一封要回的邮件、一个纠结的决策。</p><p>从那里开始就好。我在的。</p>`,40)])])}const u=s(o,[["render",e]]);export{m as __pageData,u as default};
